// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Unified Activity feed (UNION over alerts + transactions + intelligence + audit)
	// (GET /api/v1/activity)
	GetActivity(w http.ResponseWriter, r *http.Request, params GetActivityParams)
	// Dry-run validate a JWT license without installing it
	// (POST /api/v1/admin/license:verify)
	PostAdminLicenseVerify(w http.ResponseWriter, r *http.Request)
	// Reload signed policy files from the configured directory
	// (POST /api/v1/admin/policies:reload)
	PostAdminPoliciesReload(w http.ResponseWriter, r *http.Request)
	// List persisted alerts (paginated, filterable)
	// (GET /api/v1/alerts)
	GetAlerts(w http.ResponseWriter, r *http.Request, params GetAlertsParams)
	// Single alert by id
	// (GET /api/v1/alerts/{id})
	GetAlertByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Acknowledge an active alert
	// (POST /api/v1/alerts/{id}:acknowledge)
	PostAlertAcknowledge(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Dismiss an alert (terminal)
	// (POST /api/v1/alerts/{id}:dismiss)
	PostAlertDismiss(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Resolve an alert
	// (POST /api/v1/alerts/{id}:resolve)
	PostAlertResolve(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Silence an alert until a timestamp (or indefinitely)
	// (POST /api/v1/alerts/{id}:silence)
	PostAlertSilence(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// List audit events (cursor-paginated, newest first)
	// (GET /api/v1/audit/events)
	GetAuditEvents(w http.ResponseWriter, r *http.Request, params GetAuditEventsParams)
	// Username/password login with optional TOTP
	// (POST /api/v1/auth/login)
	PostAuthLogin(w http.ResponseWriter, r *http.Request)
	// Revoke the calling session
	// (POST /api/v1/auth/logout)
	PostAuthLogout(w http.ResponseWriter, r *http.Request)
	// Return the calling identity
	// (GET /api/v1/auth/me)
	GetAuthMe(w http.ResponseWriter, r *http.Request)
	// Effective permissions for the calling identity
	// (GET /api/v1/auth/me/permissions)
	GetAuthMePermissions(w http.ResponseWriter, r *http.Request)
	// Enroll the calling user in TOTP MFA
	// (POST /api/v1/auth/mfa:enroll)
	PostAuthMFAEnroll(w http.ResponseWriter, r *http.Request)
	// Confirm an enrolled MFA secret by verifying a generated OTP
	// (POST /api/v1/auth/mfa:verify)
	PostAuthMFAVerify(w http.ResponseWriter, r *http.Request)
	// Change the calling user's password
	// (POST /api/v1/auth/password:change)
	PostAuthPasswordChange(w http.ResponseWriter, r *http.Request)
	// Full RBAC registry (categories, permissions, built-in roles)
	// (GET /api/v1/auth/permissions:registry)
	GetAuthPermissionsRegistry(w http.ResponseWriter, r *http.Request)
	// Rotate the refresh token; mint a new access+refresh pair
	// (POST /api/v1/auth/refresh)
	PostAuthRefresh(w http.ResponseWriter, r *http.Request)
	// List credentials (metadata only)
	// (GET /api/v1/credentials)
	GetCredentials(w http.ResponseWriter, r *http.Request)
	// Create a credential
	// (POST /api/v1/credentials)
	PostCredentials(w http.ResponseWriter, r *http.Request)
	// Soft-delete a credential
	// (DELETE /api/v1/credentials/{id})
	DeleteCredentialByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Fetch a credential's metadata
	// (GET /api/v1/credentials/{id})
	GetCredentialByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Clone a credential into a new scope (system → host or host → host)
	// (POST /api/v1/credentials/{id}:clone)
	PostCredentialClone(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Echo the request message; exercises idempotency + audit
	// (POST /api/v1/diagnostics:echo)
	PostDiagnosticsEcho(w http.ResponseWriter, r *http.Request, params PostDiagnosticsEchoParams)
	// Stage-0 queue demo; enqueues a no-op job processed by the in-process worker
	// (POST /api/v1/diagnostics:enqueue-test-job)
	PostDiagnosticsEnqueueTestJob(w http.ResponseWriter, r *http.Request)
	// Stage-0 policy demo; evaluates the alert_thresholds policy
	// (POST /api/v1/diagnostics:evaluate-alert)
	PostDiagnosticsEvaluateAlert(w http.ResponseWriter, r *http.Request)
	// License-gated echo; requires premium_diagnostics feature
	// (POST /api/v1/diagnostics:premium-echo)
	PostDiagnosticsPremiumEcho(w http.ResponseWriter, r *http.Request, params PostDiagnosticsPremiumEchoParams)
	// Stage-0 RBAC demo; requires host:read permission
	// (POST /api/v1/diagnostics:require-host-read)
	PostDiagnosticsRequireHostRead(w http.ResponseWriter, r *http.Request, params PostDiagnosticsRequireHostReadParams)
	// Stage-0 RBAC demo; requires host:write permission
	// (POST /api/v1/diagnostics:require-host-write)
	PostDiagnosticsRequireHostWrite(w http.ResponseWriter, r *http.Request, params PostDiagnosticsRequireHostWriteParams)
	// Stage-0 RBAC+license demo; requires remediation:execute + remediation_execution feature
	// (POST /api/v1/diagnostics:require-remediation-execute)
	PostDiagnosticsRequireRemediationExecute(w http.ResponseWriter, r *http.Request, params PostDiagnosticsRequireRemediationExecuteParams)
	// 4-state connectivity breakdown (online/degraded/critical/down/never_probed)
	// (GET /api/v1/fleet/connectivity/breakdown)
	GetFleetConnectivityBreakdown(w http.ResponseWriter, r *http.Request)
	// Host counts by reachability status
	// (GET /api/v1/fleet/liveness)
	GetFleetLiveness(w http.ResponseWriter, r *http.Request)
	// Recent transactions (state changes), newest first
	// (GET /api/v1/fleet/recent-changes)
	GetFleetRecentChanges(w http.ResponseWriter, r *http.Request, params GetFleetRecentChangesParams)
	// Fleet-wide compliance score (passing/total)
	// (GET /api/v1/fleet/score)
	GetFleetScore(w http.ResponseWriter, r *http.Request, params GetFleetScoreParams)
	// Hosts with the most failing rules (descending)
	// (GET /api/v1/fleet/top-failing-hosts)
	GetFleetTopFailingHosts(w http.ResponseWriter, r *http.Request, params GetFleetTopFailingHostsParams)
	// Rules with the most failing hosts (descending)
	// (GET /api/v1/fleet/top-failing-rules)
	GetFleetTopFailingRules(w http.ResponseWriter, r *http.Request, params GetFleetTopFailingRulesParams)
	// Liveness + readiness probe (anonymous)
	// (GET /api/v1/health)
	GetHealth(w http.ResponseWriter, r *http.Request)
	// List hosts
	// (GET /api/v1/hosts)
	GetHosts(w http.ResponseWriter, r *http.Request, params GetHostsParams)
	// Create a host
	// (POST /api/v1/hosts)
	PostHosts(w http.ResponseWriter, r *http.Request)
	// Resolve the credential that will be used for a host
	// (POST /api/v1/hosts/{host_id}/credentials:resolve)
	PostHostCredentialsResolve(w http.ResponseWriter, r *http.Request, hostId openapi_types.UUID)
	// Pause/resume liveness probes for a single host
	// (PUT /api/v1/hosts/{host_id}/maintenance)
	PutHostMaintenance(w http.ResponseWriter, r *http.Request, hostId openapi_types.UUID)
	// Tail the host's monitoring-history rows (most recent first)
	// (GET /api/v1/hosts/{host_id}/monitoring/history)
	GetHostMonitoringHistory(w http.ResponseWriter, r *http.Request, hostId openapi_types.UUID, params GetHostMonitoringHistoryParams)
	// Soft-delete a host
	// (DELETE /api/v1/hosts/{id})
	DeleteHostByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Fetch a host with liveness + compliance enrichment
	// (GET /api/v1/hosts/{id})
	GetHostByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID, params GetHostByIDParams)
	// Update mutable host fields
	// (PATCH /api/v1/hosts/{id})
	PatchHostByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Synchronous on-demand reachability probe for a single host
	// (POST /api/v1/hosts/{id}/connectivity:check)
	PostHostConnectivityCheck(w http.ResponseWriter, r *http.Request, id openapi_types.UUID, params PostHostConnectivityCheckParams)
	// Synchronous on-demand OS fingerprint discovery for a single host
	// (POST /api/v1/hosts/{id}/discovery:run)
	PostHostDiscoveryRun(w http.ResponseWriter, r *http.Request, id openapi_types.UUID, params PostHostDiscoveryRunParams)
	// List OS Intelligence change events
	// (GET /api/v1/intelligence/events)
	GetIntelligenceEvents(w http.ResponseWriter, r *http.Request, params GetIntelligenceEventsParams)
	// Last full Intelligence snapshot for one host
	// (GET /api/v1/intelligence/state/{host_id})
	GetIntelligenceState(w http.ResponseWriter, r *http.Request, hostId openapi_types.UUID)
	// Get the current license state (tier, features, quotas, status)
	// (GET /api/v1/license)
	GetLicense(w http.ResponseWriter, r *http.Request)
	// List built-in roles
	// (GET /api/v1/roles)
	GetRoles(w http.ResponseWriter, r *http.Request)
	// Create a custom role
	// (POST /api/v1/roles:create)
	PostRolesCreate(w http.ResponseWriter, r *http.Request)
	// Read the connectivity-monitor runtime config + baked-in defaults
	// (GET /api/v1/system/connectivity/config)
	GetSystemConnectivityConfig(w http.ResponseWriter, r *http.Request)
	// Update connectivity-monitor runtime config
	// (PUT /api/v1/system/connectivity/config)
	PutSystemConnectivityConfig(w http.ResponseWriter, r *http.Request)
	// Read the connectivity-monitor in-process metrics + maintenance flag
	// (GET /api/v1/system/connectivity/status)
	GetSystemConnectivityStatus(w http.ResponseWriter, r *http.Request)
	// List users
	// (GET /api/v1/users)
	GetUsers(w http.ResponseWriter, r *http.Request)
	// Create a user
	// (POST /api/v1/users)
	PostUsers(w http.ResponseWriter, r *http.Request)
	// Soft-delete a user
	// (DELETE /api/v1/users/{id})
	DeleteUserByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Fetch a user
	// (GET /api/v1/users/{id})
	GetUserByID(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Assign a role to a user
	// (POST /api/v1/users/{id}/roles:assign)
	PostUserRolesAssign(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
	// Remove a role from a user
	// (POST /api/v1/users/{id}/roles:unassign)
	PostUserRolesUnassign(w http.ResponseWriter, r *http.Request, id openapi_types.UUID)
}

